func reverseString(s string) string {
	runes := []rune(s)
	for i, j := 0, len(runes)-1; i < j; i, j = i+1, j-1 {
		runes[i], runes[j] = runes[j], runes[i]
	}
	return string(runes)
}

func buildSmallestAnagram(length int, counts map[int]int) string {
	res := make([]byte, length)
	for i := 0; i < length; i++ {
		for d := 1; d <= 9; d++ {
			if counts[d] > 0 {
				res[i] = byte('0' + d)
				counts[d]--
				break
			}
		}
	}
	return string(res)
}

