				continue
			}

			candidate, err := strconv.ParseInt(entire_string, 10, 64)
			if err != nil {
				continue
			}

			if candidate > n {
				if minAnswer == -1 || candidate < minAnswer {
					minAnswer = candidate
				}
			}
		}
	}

	return minAnswer
}
